#define ELEMENTS_PER_THREAD (8)
#define FUSION_DEGREE (4)

struct half2 {
  uint16_t x;
  uint16_t y;
};

static inline uint16_t float_to_half_bits(float f) {
  union {
    float f;
    uint32_t u;
  } v;
  v.f = f;

  uint32_t sign = (v.u >> 31) & 0x1;
  uint32_t exp = (v.u >> 23) & 0xFF;
  uint32_t mant = v.u & 0x7FFFFF;

  uint16_t hsign = static_cast<uint16_t>(sign << 15);

  if (exp == 255) {
    if (mant != 0) return static_cast<uint16_t>(hsign | 0x7E00);
    return static_cast<uint16_t>(hsign | 0x7C00);
  }

  int32_t new_exp = static_cast<int32_t>(exp) - 127 + 15;
  if (new_exp >= 31) {
    return static_cast<uint16_t>(hsign | 0x7C00);
  }
  if (new_exp <= 0) {
    if (new_exp < -10) return hsign;
    mant |= 0x800000;
    uint32_t shift = static_cast<uint32_t>(14 - new_exp);
    uint16_t hmant = static_cast<uint16_t>(mant >> shift);
    if ((mant >> (shift - 1)) & 1) hmant++;
    return static_cast<uint16_t>(hsign | hmant);
  }

  uint16_t hexp = static_cast<uint16_t>(new_exp << 10);
  uint16_t hmant = static_cast<uint16_t>(mant >> 13);
  if (mant & 0x00001000) hmant++;
  return static_cast<uint16_t>(hsign | hexp | (hmant & 0x03FF));
}

static inline float half_bits_to_float(uint16_t h) {
  uint32_t sign = (h >> 15) & 0x1;
  uint32_t exp = (h >> 10) & 0x1F;
  uint32_t mant = h & 0x03FF;

  uint32_t fsign = sign << 31;
  uint32_t fexp;
  uint32_t fmant;

  if (exp == 0) {
    if (mant == 0) {
      fexp = 0;
      fmant = 0;
    } else {
      int e = -1;
      uint32_t m = mant;
      do {
        e++;
        m <<= 1;
      } while ((m & 0x0400) == 0);
      m &= 0x03FF;
      fexp = static_cast<uint32_t>(127 - 15 - e) << 23;
      fmant = m << 13;
    }
  } else if (exp == 31) {
    fexp = 0xFFu << 23;
    fmant = mant << 13;
  } else {
    fexp = static_cast<uint32_t>(exp - 15 + 127) << 23;
    fmant = mant << 13;
  }

  union {
    uint32_t u;
    float f;
  } out;
  out.u = fsign | fexp | fmant;
  return out.f;
}

template <class T>
inline T conv_int(const int i) {
  return static_cast<T>(i);
}

template <>
inline half2 conv_int<half2>(const int i) {
  uint16_t h = float_to_half_bits(static_cast<float>(i));
  return half2{h, h};
}

template <class T>
inline T mad(const T a, const T b, const T c) {
  return a * b + c;
}

template <>
inline half2 mad<half2>(const half2 a, const half2 b, const half2 c) {
  float ax = half_bits_to_float(a.x);
  float ay = half_bits_to_float(a.y);
  float bx = half_bits_to_float(b.x);
  float by = half_bits_to_float(b.y);
  float cx = half_bits_to_float(c.x);
  float cy = half_bits_to_float(c.y);
  return half2{float_to_half_bits(ax * bx + cx), float_to_half_bits(ay * by + cy)};
}

template <class T>
inline bool equal(const T a, const T b) {
  return a == b;
}

template <>
inline bool equal<half2>(const half2 a, const half2 b) {
  return (a.x == b.x) && (a.y == b.y);
}

template <class T, int blockdim, unsigned int granularity, unsigned int fusion_degree,
          unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T* g_data, int grid_dim_x) {
  (void)TemperateUnroll;
  const unsigned int blockSize = blockdim;
  const int stride = static_cast<int>(blockSize);
  const int big_stride = grid_dim_x * static_cast<int>(blockSize) * static_cast<int>(granularity);

#pragma omp parallel for collapse(2) schedule(static)
  for (int blockIdx = 0; blockIdx < grid_dim_x; blockIdx++) {
    for (int threadIdx = 0; threadIdx < static_cast<int>(blockSize); threadIdx++) {
      int idx = blockIdx * static_cast<int>(blockSize) * static_cast<int>(granularity) + threadIdx;

      T tmps[granularity];
      for (unsigned int k = 0; k < fusion_degree; k++) {
        for (unsigned int j = 0; j < granularity; j++) {
          tmps[j] = g_data[idx + static_cast<int>(j) * stride + static_cast<int>(k) * big_stride];
          for (unsigned int i = 0; i < compute_iterations; i++) {
            tmps[j] = mad(tmps[j], tmps[j], seed);
          }
        }

        T sum = conv_int<T>(0);
        for (unsigned int j = 0; j < granularity; j += 2) {
          sum = mad(tmps[j], tmps[j + 1], sum);
        }

        if (equal(sum, conv_int<T>(-1))) {
          g_data[idx + static_cast<int>(k) * big_stride] = sum;
        }
      }
    }
  }
}

void runbench_warmup(double* cd, long size) {
  const long reduced_grid_size = size / (ELEMENTS_PER_THREAD) / 128;
  const int BLOCK_SIZE = 256;
  const int TOTAL_REDUCED_BLOCKS = static_cast<int>(reduced_grid_size / BLOCK_SIZE);
  benchmark_func<short, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true>(
      static_cast<short>(1), reinterpret_cast<short*>(cd), TOTAL_REDUCED_BLOCKS);
}

template <typename Func>
static inline float measure_ms(Func&& fn) {
  double start = omp_get_wtime();
  fn();
  double stop = omp_get_wtime();
  return static_cast<float>((stop - start) * 1000.0);
}

int out_config = 1;

template <unsigned int compute_iterations>
void runbench(double* cd, long size, bool doHalfs) {
  (void)out_config;
  const long compute_grid_size = size / ELEMENTS_PER_THREAD / FUSION_DEGREE;
  const int BLOCK_SIZE = 256;
  const int TOTAL_BLOCKS = static_cast<int>(compute_grid_size / BLOCK_SIZE);
  const long long computations =
      (ELEMENTS_PER_THREAD * (long long)compute_grid_size +
       (2 * ELEMENTS_PER_THREAD * compute_iterations) * (long long)compute_grid_size) *
      FUSION_DEGREE;
  const long long memoryoperations = size;

  float kernel_time_mad_sp = measure_ms([&]() {
    benchmark_func<float, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations,
                   false>(1.0f, reinterpret_cast<float*>(cd), TOTAL_BLOCKS);
  });

  float kernel_time_mad_dp = measure_ms([&]() {
    benchmark_func<double, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations,
                   false>(1.0, cd, TOTAL_BLOCKS);
  });

  float kernel_time_mad_hp = 0.f;
  if (doHalfs) {
    half2 h_ones;
    h_ones.x = 15360;
    h_ones.y = 15360;
    kernel_time_mad_hp = measure_ms([&]() {
      benchmark_func<half2, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations,
                     false>(h_ones, reinterpret_cast<half2*>(cd), TOTAL_BLOCKS);
    });
  }

  float kernel_time_mad_int = measure_ms([&]() {
    benchmark_func<int, BLOCK_SIZE, ELEMENTS_PER_THREAD, FUSION_DEGREE, compute_iterations,
                   true>(1, reinterpret_cast<int*>(cd), TOTAL_BLOCKS);
  });

  printf(
      "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
      "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
      compute_iterations,
      ((double)computations) / ((double)memoryoperations * sizeof(float)),
      kernel_time_mad_sp,
      ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(double)),
      kernel_time_mad_dp,
      ((double)computations) / kernel_time_mad_dp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)2 * computations) / ((double)memoryoperations * sizeof(half2)),
      kernel_time_mad_hp,
      ((double)2 * computations) / kernel_time_mad_hp * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(half2)) / kernel_time_mad_hp * 1000. /
          (1000. * 1000. * 1000.),
      ((double)computations) / ((double)memoryoperations * sizeof(int)),
      kernel_time_mad_int,
      ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
      ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
          (1000. * 1000. * 1000.));
}

